@module fxRouting  src=fxRouting.lua  loc=133  sha=untracked  mode=namespace

# Module-level constants
  @const M = {}  @ 8
  @const ALPHA = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123...  @ 12
  @const DEC = {}  @ 13

# Private functions
  -- Base64
  @fn b64decode(s)  @ 16
  @fn b64encode(s)  @ 36
  -- Line splitting that round-trips the chunk's trailing-newline shape
  @fn splitLines(s)  @ 58
  @fn joinLines(lines, hasTrailing)  @ 66
  -- FX-block lookup
  @fn findFxBlock(lines, fxIdx)  @ 75
      -- Find the (fxIdx+1)-th non-JS FX block in the chunk (0-indexed).
      -- JSFX blocks have no routing trailer and are skipped.
      -- Returns (headerLineIdx, firstBase64LineIdx, trailerLineIdx) or nil.
  -- Bit-level patch
  @fn orBitAt(line, byteIdx, mask)  @ 99

# Public API (M.*)
  @api M.setOutputDisabled(chunk, fxIdx)  @ 118
      -- Set the "output bus disabled" bit (0x02) on the fxIdx-th FX block
      -- (0-indexed) of an FXCHAIN-bearing track-state chunk. Read-modify-
      -- write on the bit alone: every other flag bit, in_bus, and out_bus
      -- are preserved. The flag is mirrored in two places — the trailer
      -- line and the penultimate byte of the first base64 line — and the
      -- patch is applied to both. Idempotent. Returns (newChunk, ok).
